import { useInsertionEffect } from 'react';
import { ensurePresetStyles } from './ensure-preset-styles';
/**
 * Normalizes a preset prop to a value (or null) and ensures its CSS
 * is injected once into `document.head`.
 *
 * Works with any preset that has `{ css, name }` - animation presets
 * (TAnimationPreset) satisfies this shape.
 */
export function usePresetStyles({
  preset
}) {
  const resolved = preset != null && preset !== false ? preset : null;
  useInsertionEffect(() => {
    if (resolved) {
      ensurePresetStyles({
        preset: resolved
      });
    }
  }, [resolved]);
  return resolved;
}